args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?artist ?label WHERE {
  ?cover wdt:P144 wd:Q7786031.
  ?cover wdt:P577 ?date.
  ?cover wdt:P175 ?artist.
  ?artist wdt:P136 wd:Q186710.
  FILTER(YEAR(?date) = 1996)
  OPTIONAL { ?artist rdfs:label ?label FILTER(LANG(?label) = 'en') }
}
